# --- plot helper (hidden) — the Caesar shift as a mapping ---
# The shifted-alphabet curve is built by calling the student's OWN shift_letter
# on every letter. Falls back to the built-in shift until it works. The 'no
# shift' diagonal is a fixed comparison.
def __identity():
    return [[i, i] for i in range(26)]

def __shift_map_ref(n):
    return [[i, (i + n) % 26] for i in range(26)]

def __shift_map_student(n):
    pts = []
    for i in range(26):
        landed = shift_letter(chr(97 + i), n)   # <- the STUDENT's function
        pts.append([i, ord(landed) - 97])
    return pts

def __plot(n):
    try:
        m = __shift_map_student(n)
        if m and len(m) == 26:
            shifted = {"name": "shifted alphabet (your key)", "points": m, "highlight": True}
        else:
            raise ValueError()
    except Exception:
        shifted = {"name": "shifted alphabet (key)", "points": __shift_map_ref(n), "highlight": True}
    return [shifted, {"name": "no shift (key = 0)", "points": __identity(), "highlight": False}]
